  <style>
    :root {
      --bg: #f3efe8;
      --panel: #fffdf9;
      --text: #201d18;
      --muted: #6f6a63;
      --accent: #8c5e3c;
      --accent-strong: #6d4527;
      --border: rgba(32, 29, 24, 0.12);
      --radius: 18px;
      --shadow: 0 18px 40px rgba(32, 29, 24, 0.08);
    }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      min-height: 100vh;
      font-family: ''Work Sans'', system-ui, sans-serif;
      background:
        radial-gradient(circle at top left, rgba(140, 94, 60, 0.10), transparent 30%),
        linear-gradient(180deg, #f7f3ed 0%, var(--bg) 100%);
      color: var(--text);
      display: grid;
      place-items: center;
      padding: 24px;
    }
    .panel {
      width: min(760px, 100%);
      background: var(--panel);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      box-shadow: var(--shadow);
      padding: 32px;
    }
    .eyebrow {
      display: inline-block;
      padding: 8px 12px;
      border-radius: 999px;
      background: rgba(140, 94, 60, 0.10);
      color: var(--accent-strong);
      font-size: 14px;
      font-weight: 700;
      letter-spacing: 0.04em;
      text-transform: uppercase;
      margin-bottom: 20px;
    }
    h1 {
      margin: 0 0 16px;
      font-family: ''Instrument Serif'', Georgia, serif;
      font-size: clamp(2.2rem, 6vw, 4.4rem);
      line-height: 0.95;
      max-width: 10ch;
    }
    p {
      margin: 0 0 24px;
      color: var(--muted);
      font-size: 1.05rem;
      max-width: 58ch;
    }
    .grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
      gap: 16px;
      margin: 28px 0;
    }
    .mini-card {
      padding: 18px;
      border: 1px solid var(--border);
      border-radius: 14px;
      background: #fffaf4;
    }
    .mini-card strong {
      display: block;
      margin-bottom: 8px;
      font-size: 1rem;
    }
    .mini-card span {
      color: var(--muted);
      font-size: 0.95rem;
    }
    .actions {
      display: flex;
      flex-wrap: wrap;
      gap: 12px;
      margin-top: 12px;
    }
    .btn {
      min-height: 46px;
      padding: 0 18px;
      border-radius: 12px;
      border: 1px solid transparent;
      font-weight: 700;
      font-size: 0.95rem;
      cursor: pointer;
    }
    .btn-primary {
      background: var(--accent);
      color: white;
    }
    .btn-primary:hover { background: var(--accent-strong); }
    .btn-secondary {
      background: transparent;
      color: var(--text);
      border-color: var(--border);
    }
  </style>
</head>
